#include<bits/stdc++.h>
using namespace std;

int main(){
    int n,anns=0;
    cin>>n;
    for(int i=1;i<=n;i++){
        int x=i,ans,flag=1;
        ans=x%10;
        while(x){
            int m=x%10;
            x/=10;
            if(ans!=m) flag=0;
        }
        if(flag) anns++;
    } 
    cout<<anns;
    return 0;
}
